}

func (v VMConfig) Validate() error {
	if v.PushURL == "" {
		return nil
	}
	if v.BatchSize <= 0 {
		v.BatchSize = 500
	}
	if v.FlushInterval <= 0 {
		v.FlushInterval = 10 * time.Second
	}
	if v.BufferSize <= 0 {
		v.BufferSize = 10000
	}
	return nil
}

type RetryConfig struct {
