package metrics

import (
	"sort"
	"strings"
	"sync"
	"time"
)

type MetricType string

const (
	TypeGauge     MetricType = "gauge"
	TypeCounter   MetricType = "counter"
	TypeHistogram MetricType = "histogram"
	TypeUntyped   MetricType = "untyped"
)

type Metric struct {
	Name      string
	Labels    map[string]string
	Value     float64
	Timestamp time.Time
	Type      MetricType
}

func (m *Metric) LabelString() string {
	if len(m.Labels) == 0 {
		return ""
	}
	keys := make([]string, 0, len(m.Labels))
	for k := range m.Labels {
		keys = append(keys, k)
	}
	sort.Strings(keys)
	var b strings.Builder
	for i, k := range keys {
		if i > 0 {
			b.WriteByte(',')
		}
		b.WriteString(k)
		b.WriteByte('=')
		b.WriteString(m.Labels[k])
	}
	return b.String()
}

type MetricBatch []Metric

type MetricPool struct {
	pool sync.Pool
}

func NewMetricPool() *MetricPool {
	return &MetricPool{
		pool: sync.Pool{
			New: func() any {
				return &Metric{}
			},
		},
	}
}

func (p *MetricPool) Get() *Metric {
	return p.pool.Get().(*Metric)
}

func (p *MetricPool) Put(m *Metric) {
	m.Name = ""
	m.Labels = nil
	m.Value = 0
	m.Type = ""
	m.Timestamp = time.Time{}
	p.pool.Put(m)
}

package metrics

import "sort"

type Histogram struct {
	Buckets []float64
	Counts  []uint64
	Count   uint64
	Sum     float64
}

func NewHistogram(buckets []float64) *Histogram {
	sorted := make([]float64, len(buckets))
	copy(sorted, buckets)
	sort.Float64s(sorted)

	return &Histogram{
		Buckets: sorted,
		Counts:  make([]uint64, len(sorted)),
	}
}

func (h *Histogram) Observe(value float64) {
	h.Count++
	h.Sum += value

	for i, b := range h.Buckets {
		if value <= b {
			h.Counts[i]++
		}
	}
}

func (h *Histogram) Reset() {
	h.Count = 0
	h.Sum = 0
	for i := range h.Counts {
		h.Counts[i] = 0
	}
}

func (h *Histogram) Metrics(name string, labels map[string]string, ts int64) []Metric {
	merge := make(map[string]string, len(labels)+1)
	for k, v := range labels {
		merge[k] = v
	}

	var ms []Metric

	ms = append(ms, Metric{
		Name:      name + "_count",
		Labels:    copyMap(labels),
		Value:     float64(h.Count),
		Timestamp: timeFromUnix(ts),
		Type:      TypeGauge,
	})

	ms = append(ms, Metric{
		Name:      name + "_sum",
		Labels:    copyMap(labels),
		Value:     h.Sum,
		Timestamp: timeFromUnix(ts),
		Type:      TypeGauge,
	})

	for i, bucket := range h.Buckets {
		merge["le"] = formatFloat(bucket)
		ms = append(ms, Metric{
			Name:      name + "_bucket",
			Labels:    copyMap(merge),
			Value:     float64(h.Counts[i]),
			Timestamp: timeFromUnix(ts),
			Type:      TypeGauge,
		})
	}

	merge["le"] = "+Inf"
	ms = append(ms, Metric{
		Name:      name + "_bucket",
		Labels:    copyMap(merge),
		Value:     float64(h.Count),
		Timestamp: timeFromUnix(ts),
		Type:      TypeGauge,
	})

	return ms
}

func copyMap(m map[string]string) map[string]string {
	if m == nil {
		return nil
	}
	c := make(map[string]string, len(m))
	for k, v := range m {
		c[k] = v
	}
	return c
}

func timeFromUnix(ts int64) time.Time {
	return time.Unix(ts, 0)
}

func formatFloat(f float64) string {
	if f == float64(int(f)) {
		return formatInt(int(f))
	}
	return formatFloatPrecise(f)
}

func formatInt(i int) string {
	if i == 0 {
		return "0"
	}
	var buf [20]byte
	pos := len(buf)
	neg := i < 0
	if neg {
		i = -i
	}
	for i > 0 {
		pos--
		buf[pos] = byte('0' + i%10)
		i /= 10
	}
	if neg {
		pos--
		buf[pos] = '-'
	}
	return string(buf[pos:])
}

func formatFloatPrecise(f float64) string {
	return formatFloat(f) + ".0"
}

package metrics

import (
	"sort"
	"strconv"
	"time"
)

type Histogram struct {
	Buckets []float64
	Counts  []uint64
	Count   uint64
	Sum     float64
}

func NewHistogram(buckets []float64) *Histogram {
	sorted := make([]float64, len(buckets))
	copy(sorted, buckets)
	sort.Float64s(sorted)

	return &Histogram{
		Buckets: sorted,
		Counts:  make([]uint64, len(sorted)),
	}
}

func (h *Histogram) Observe(value float64) {
	h.Count++
	h.Sum += value

	for i, b := range h.Buckets {
		if value <= b {
			h.Counts[i]++
		}
	}
}

func (h *Histogram) Reset() {
	h.Count = 0
	h.Sum = 0
	for i := range h.Counts {
		h.Counts[i] = 0
	}
}

func (h *Histogram) Metrics(name string, labels map[string]string, ts int64) []Metric {
	merge := make(map[string]string, len(labels)+1)
	for k, v := range labels {
		merge[k] = v
	}

	now := time.Unix(ts, 0)
	var ms []Metric

	ms = append(ms, Metric{
		Name:      name + "_count",
		Labels:    copyMapLabels(labels),
		Value:     float64(h.Count),
		Timestamp: now,
		Type:      TypeGauge,
	})

	ms = append(ms, Metric{
		Name:      name + "_sum",
		Labels:    copyMapLabels(labels),
		Value:     h.Sum,
		Timestamp: now,
		Type:      TypeGauge,
	})

	for i, bucket := range h.Buckets {
		merge["le"] = floatStr(bucket)
		ms = append(ms, Metric{
			Name:      name + "_bucket",
			Labels:    copyMapLabels(merge),
			Value:     float64(h.Counts[i]),
			Timestamp: now,
			Type:      TypeGauge,
		})
	}

	merge["le"] = "+Inf"
	ms = append(ms, Metric{
		Name:      name + "_bucket",
		Labels:    copyMapLabels(merge),
		Value:     float64(h.Count),
		Timestamp: now,
		Type:      TypeGauge,
	})

	return ms
}

func floatStr(f float64) string {
	return strconv.FormatFloat(f, 'f', -1, 64)
}

func copyMapLabels(m map[string]string) map[string]string {
	if m == nil {
		return nil
	}
	c := make(map[string]string, len(m))
	for k, v := range m {
		c[k] = v
	}
	return c
}

package metrics

import (
	"sort"
	"sync"
)

type Registry struct {
	mu      sync.RWMutex
	metrics map[string][]Metric
}

func NewRegistry() *Registry {
	return &Registry{
		metrics: make(map[string][]Metric),
	}
}

func (r *Registry) Store(key string, ms []Metric) {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.metrics[key] = ms
}

func (r *Registry) Get(key string) []Metric {
	r.mu.RLock()
	defer r.mu.RUnlock()
	return r.metrics[key]
}

func (r *Registry) Keys() []string {
	r.mu.RLock()
	defer r.mu.RUnlock()
	keys := make([]string, 0, len(r.metrics))
	for k := range r.metrics {
		keys = append(keys, k)
	}
	sort.Strings(keys)
	return keys
}

func (r *Registry) Delete(key string) {
	r.mu.Lock()
	defer r.mu.Unlock()
	delete(r.metrics, key)
}

func (r *Registry) All() map[string][]Metric {
	r.mu.RLock()
	defer r.mu.RUnlock()
	c := make(map[string][]Metric, len(r.metrics))
	for k, v := range r.metrics {
		ms := make([]Metric, len(v))
		copy(ms, v)
		c[k] = ms
	}
	return c
}

package output

import (
	"sync"

	"probe-agent/internal/metrics"
)

type RingBuffer struct {
	mu    sync.Mutex
	data  []metrics.Metric
	head  int
	tail  int
	count int
	size  int
}

func NewRingBuffer(size int) *RingBuffer {
	if size <= 0 {
		size = 10000
	}
	return &RingBuffer{
		data: make([]metrics.Metric, size),
		size: size,
	}
}

func (b *RingBuffer) Push(m metrics.Metric) {
	b.mu.Lock()
	defer b.mu.Unlock()

	b.data[b.tail] = m
	b.tail = (b.tail + 1) % b.size
	if b.count == b.size {
		b.head = (b.head + 1) % b.size
	} else {
		b.count++
	}
}

func (b *RingBuffer) PopN(n int) []metrics.Metric {
	b.mu.Lock()
	defer b.mu.Unlock()

	if n <= 0 || b.count == 0 {
		return nil
	}
	if n > b.count {
		n = b.count
	}

	result := make([]metrics.Metric, n)
	for i := 0; i < n; i++ {
		result[i] = b.data[b.head]
		b.head = (b.head + 1) % b.size
	}
	b.count -= n

	return result
}

func (b *RingBuffer) Len() int {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.count
}

func (b *RingBuffer) PushBatch(ms []metrics.Metric) {
	b.mu.Lock()
	defer b.mu.Unlock()

	for _, m := range ms {
		b.data[b.tail] = m
		b.tail = (b.tail + 1) % b.size
		if b.count == b.size {
			b.head = (b.head + 1) % b.size
		} else {
			b.count++
		}
	}
}

package output

import (
	"strconv"
	"strings"
	"sync"
	"time"

	"probe-agent/internal/metrics"
)

type Batcher struct {
	mu       sync.Mutex
	buf      strings.Builder
	count    int
	batchSize int
	interval time.Duration
}

func NewBatcher(batchSize int, interval time.Duration) *Batcher {
	return &Batcher{
		batchSize: batchSize,
		interval:  interval,
	}
}

func (b *Batcher) Add(ms []metrics.Metric) string {
	b.mu.Lock()
	defer b.mu.Unlock()

	for _, m := range ms {
		b.writeMetric(m)
	}

	if b.count >= b.batchSize {
		return b.flush()
	}
	return ""
}

func (b *Batcher) Flush() string {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.flush()
}

func (b *Batcher) flush() string {
	if b.count == 0 {
		return ""
	}
	data := b.buf.String()
	b.buf.Reset()
	b.count = 0
	return data
}

func (b *Batcher) writeMetric(m metrics.Metric) {
	b.buf.WriteString(m.Name)

	if len(m.Labels) > 0 {
		b.buf.WriteByte('{')
		first := true
		keys := make([]string, 0, len(m.Labels))
		for k := range m.Labels {
			keys = append(keys, k)
		}
		sortStrings(keys)
		for _, k := range keys {
			if !first {
				b.buf.WriteByte(',')
			}
			b.buf.WriteString(k)
			b.buf.WriteString(`="`)
			b.buf.WriteString(m.Labels[k])
			b.buf.WriteByte('"')
			first = false
		}
		b.buf.WriteByte('}')
	}

	b.buf.WriteByte(' ')
	b.buf.WriteString(float64Str(m.Value))
	b.buf.WriteByte(' ')
	b.buf.WriteString(strconv.FormatInt(m.Timestamp.Unix(), 10))
	b.buf.WriteByte('\n')
	b.count++
}

func float64Str(f float64) string {
	return strconv.FormatFloat(f, 'f', -1, 64)
}

func sortStrings(s []string) {
	for i := 0; i < len(s)-1; i++ {
		for j := i + 1; j < len(s); j++ {
			if s[i] > s[j] {
				s[i], s[j] = s[j], s[i]
			}
		}
	}
}

package output

import (
	"bytes"
	"context"
	"fmt"
	"io"
	"net/http"
	"time"

	"probe-agent/internal/config"
	"probe-agent/internal/metrics"
	"go.uber.org/zap"
)

type VMPusher struct {
	cfg     config.VMConfig
	client  *http.Client
	buffer  *RingBuffer
	batcher *Batcher
	logger  *zap.Logger
	ctx     context.Context
	cancel  context.CancelFunc
	done    chan struct{}
}

func NewVMPusher(cfg config.VMConfig, logger *zap.Logger) *VMPusher {
	client := &http.Client{
		Timeout: 30 * time.Second,
		Transport: &http.Transport{
			MaxIdleConns:    10,
			IdleConnTimeout: 90 * time.Second,
		},
	}

	return &VMPusher{
		cfg:     cfg,
		client:  client,
		buffer:  NewRingBuffer(cfg.BufferSize),
		batcher: NewBatcher(cfg.BatchSize, cfg.FlushInterval),
		logger:  logger.Named("vmpush"),
		done:    make(chan struct{}),
	}
}

func (v *VMPusher) Name() string {
	return "victoria_metrics"
}

func (v *VMPusher) Start() error {
	v.ctx, v.cancel = context.WithCancel(context.Background())
	go v.flushLoop()
	v.logger.Info("vm pusher started",
		zap.String("push_url", v.cfg.PushURL),
		zap.Duration("flush_interval", v.cfg.FlushInterval),
		zap.Int("batch_size", v.cfg.BatchSize),
	)
	return nil
}

func (v *VMPusher) Stop() error {
	if v.cancel != nil {
		v.cancel()
	}
	<-v.done

	if data := v.batcher.Flush(); data != "" {
		v.push(data)
	}
	return nil
}

func (v *VMPusher) Write(ms []metrics.Metric) error {
	v.buffer.PushBatch(ms)
	return nil
}

func (v *VMPusher) flushLoop() {
	ticker := time.NewTicker(v.cfg.FlushInterval)
	defer ticker.Stop()
	defer close(v.done)

	for {
		select {
		case <-v.ctx.Done():
			return
		case <-ticker.C:
			v.flush()
		}
	}
}

func (v *VMPusher) flush() {
	metrics := v.buffer.PopN(v.cfg.BatchSize)
	if len(metrics) == 0 {
		return
	}

	data := v.batcher.Add(metrics)
	if data == "" {
		return
	}

	v.push(data)
}

func (v *VMPusher) push(data string) {
	for attempt := 0; attempt <= v.cfg.Retry.MaxRetries; attempt++ {
		if err := v.pushOnce(data); err != nil {
			v.logger.Error("push failed",
				zap.Int("attempt", attempt+1),
				zap.Error(err),
			)
			if attempt < v.cfg.Retry.MaxRetries {
				backoff := v.cfg.Retry.InitialBackoff * time.Duration(1<<uint(attempt))
				if backoff > v.cfg.Retry.MaxBackoff {
					backoff = v.cfg.Retry.MaxBackoff
				}
				select {
				case <-v.ctx.Done():
					return
				case <-time.After(backoff):
				}
			}
			return
		}
		return
	}
}

func (v *VMPusher) pushOnce(data string) error {
	req, err := http.NewRequestWithContext(v.ctx, http.MethodPost, v.cfg.PushURL, bytes.NewBufferString(data))
	if err != nil {
		return fmt.Errorf("create request: %w", err)
	}
	req.Header.Set("Content-Type", "text/plain; version=0.0.4")

	resp, err := v.client.Do(req)
	if err != nil {
		return fmt.Errorf("http post: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode/100 != 2 {
		body, _ := io.ReadAll(resp.Body)
		return fmt.Errorf("unexpected status %d: %s", resp.StatusCode, string(body))
	}

	return nil
}

