package main

import (
	"context"
	"flag"
	"os"
	"os/signal"
	"syscall"

	"probe-agent/internal/config"
	"probe-agent/internal/logger"
	"probe-agent/internal/metrics"
	"probe-agent/internal/output"
	"go.uber.org/zap"
)

func main() {
	var configDir string
	flag.StringVar(&configDir, "config-dir", "./config", "path to config directory")
	flag.Parse()

	cfg, err := config.Load(configDir)
	if err != nil {
		os.Stderr.WriteString("failed to load config: " + err.Error() + "\n")
		os.Exit(1)
	}

	if err := logger.Init(cfg.Global.LogLevel); err != nil {
		os.Stderr.WriteString("failed to init logger: " + err.Error() + "\n")
		os.Exit(1)
	}

	logger.Log.Info("starting probe-agent",
		zap.String("config_dir", configDir),
	)

	registry := metrics.NewRegistry()

	pipeline, err := output.NewPipelineFromConfig(output.PipelineConfig{
		VMConfig: cfg.Global.VictoriaMetrics,
		Registry: registry,
		Logger:   logger.Log,
	})
	if err != nil {
		logger.Log.Error("failed to create pipeline", zap.Error(err))
		os.Exit(1)
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	if err := pipeline.Start(); err != nil {
		logger.Log.Error("failed to start pipeline", zap.Error(err))
		os.Exit(1)
	}

	stop := make(chan os.Signal, 1)
	signal.Notify(stop, syscall.SIGINT, syscall.SIGTERM)

	reload := make(chan os.Signal, 1)
	signal.Notify(reload, syscall.SIGHUP)

	go func() {
		for {
			select {
			case <-reload:
				logger.Log.Info("reloading config")
				newCfg, err := config.Load(configDir)
				if err != nil {
					logger.Log.Error("failed to reload config", zap.Error(err))
					continue
				}
				cfg = newCfg
				logger.Log.Info("config reloaded")
			case <-ctx.Done():
				return
			}
		}
	}()

	logger.Log.Info("probe-agent started")

	<-stop
	logger.Log.Info("shutting down...")
	cancel()
	pipeline.Stop()
}

