package mcp

import (
	"net/http"
	"strings"
	"sync"
)

type APIKeyAuth struct {
	keys map[string]struct{}
	mu   sync.RWMutex
}

func NewAPIKeyAuth(keys []string) *APIKeyAuth {
	a := &APIKeyAuth{
		keys: make(map[string]struct{}, len(keys)),
	}
	for _, k := range keys {
		a.keys[k] = struct{}{}
	}
	return a
}

func (a *APIKeyAuth) UpdateKeys(keys []string) {
	a.mu.Lock()
	defer a.mu.Unlock()
	newKeys := make(map[string]struct{}, len(keys))
	for _, k := range keys {
		newKeys[k] = struct{}{}
	}
	a.keys = newKeys
}

func (a *APIKeyAuth) Validate(r *http.Request) bool {
	auth := r.Header.Get("Authorization")
	if !strings.HasPrefix(auth, "Bearer ") {
		return false
	}
	key := strings.TrimPrefix(auth, "Bearer ")

	a.mu.RLock()
	defer a.mu.RUnlock()
	_, ok := a.keys[key]
	return ok
}

func AuthMiddleware(next http.Handler, auth *APIKeyAuth) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if !auth.Validate(r) {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusUnauthorized)
			w.Write([]byte(`{"error":"unauthorized: invalid or missing api key"}`))
			return
		}
		next.ServeHTTP(w, r)
	})
}

package mcp

import (
	"context"
	"fmt"
	"net/http"
	"sync"

	"probe-agent/internal/config"
	"probe-agent/internal/metrics"
	"github.com/mark3labs/mcp-go/mcp"
	"github.com/mark3labs/mcp-go/server"
	"go.uber.org/zap"
)

type Dependencies struct {
	Registry *metrics.Registry
	Config   *config.Config
	Logger   *zap.Logger
}

type Server struct {
	mcpServer  *server.MCPServer
	httpServer *server.StreamableHTTPServer
	auth       *APIKeyAuth
	deps       Dependencies
	cfg        config.MCPConfig
	handler    http.Handler
	httpSrv    *http.Server
	mu         sync.Mutex
}

func New(deps Dependencies, cfg config.MCPConfig) (*Server, error) {
	s := &Server{
		deps: deps,
		cfg:  cfg,
	}

	s.mcpServer = server.NewMCPServer(
		"probe-agent",
		"1.0.0",
		server.WithInstructions("Network monitoring agent - ICMP, DNS, SNMP probes"),
		server.WithToolCapabilities(true),
	)

	s.registerTools()

	s.httpServer = server.NewStreamableHTTPServer(
		s.mcpServer,
		server.WithEndpointPath("/mcp"),
	)

	handler := http.Handler(s.httpServer)

	if cfg.Auth.Type == "api_key" && len(cfg.Auth.Keys) > 0 {
		s.auth = NewAPIKeyAuth(cfg.Auth.Keys)
		handler = AuthMiddleware(handler, s.auth)
		deps.Logger.Info("mcp api key auth enabled")
	}

	s.handler = handler

	return s, nil
}

func (s *Server) Handler() http.Handler {
	return s.handler
}

func (s *Server) Start(addr string) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.httpSrv != nil {
		return fmt.Errorf("mcp server already started")
	}

	s.httpSrv = &http.Server{
		Addr:    addr,
		Handler: s.handler,
	}

	s.deps.Logger.Info("mcp server starting",
		zap.String("addr", addr),
		zap.String("endpoint", "/mcp"),
	)

	go func() {
		if err := s.httpSrv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			s.deps.Logger.Error("mcp server error", zap.Error(err))
		}
	}()

	return nil
}

func (s *Server) Stop(ctx context.Context) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.httpSrv == nil {
		return nil
	}

	return s.httpSrv.Shutdown(ctx)
}

func (s *Server) registerTools() {
	s.registerGetTargets()
	s.registerGetMetrics()
}

func (s *Server) MakeLabelsJSON(labels map[string]string) string {
	if len(labels) == 0 {
		return "{}"
	}
	return fmt.Sprintf("%v", labels)
}

func argString(req mcp.CallToolRequest, name string) string {
	if req.Params.Arguments == nil {
		return ""
	}
	v, ok := req.Params.Arguments[name]
	if !ok {
		return ""
	}
	s, _ := v.(string)
	return s
}

