package mcp

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"

	"probe-agent/internal/config"
	"probe-agent/internal/metrics"
	"github.com/mark3labs/mcp-go/mcp"
)

func (s *Server) registerGetTargets() {
	tool := mcp.NewTool("get_targets",
		mcp.WithDescription("List all monitoring targets with their module, host, and labels"),
		mcp.WithString("module",
			mcp.Description("Filter by module: icmp, snmp, dns (empty returns all)"),
		),
	)

	s.mcpServer.AddTool(tool, s.handleGetTargets)
}

func (s *Server) handleGetTargets(ctx context.Context, req mcp.CallToolRequest) (*mcp.CallToolResult, error) {
	filter := argString(req, "module")

	type targetInfo struct {
		Host   string            `json:"host"`
		Module string            `json:"module"`
		Labels map[string]string `json:"labels"`
		Up     bool              `json:"up"`
	}

	var targets []targetInfo

	if filter == "" || filter == "icmp" {
		for _, t := range s.deps.Config.ICMP.Targets {
			targets = append(targets, targetInfo{
				Host:   t.Host,
				Module: "icmp",
				Labels: t.Labels,
				Up:     checkUp(s.deps.Registry, "icmp/"+t.Host),
			})
		}
	}

	if filter == "" || filter == "dns" {
		for _, t := range s.deps.Config.DNS.Targets {
			targets = append(targets, targetInfo{
				Host:   t.Domain,
				Module: "dns",
				Labels: mergeLabels(t.Labels, "server", t.Server, "record_type", t.RecordType),
				Up:     checkUp(s.deps.Registry, "dns/"+t.Domain+"|"+t.Server),
			})
		}
	}

	if filter == "" || filter == "snmp" {
		for _, t := range s.deps.Config.SNMP.Targets {
			targets = append(targets, targetInfo{
				Host:   t.Host,
				Module: "snmp",
				Labels: t.Labels,
				Up:     checkUp(s.deps.Registry, "snmp/"+t.Host),
			})
		}
	}

	if len(targets) == 0 {
		return mcp.NewToolResultText("No targets found."), nil
	}

	var b strings.Builder
	b.WriteString(fmt.Sprintf("Found %d target(s):\n\n", len(targets)))
	for _, t := range targets {
		status := "UP"
		if !t.Up {
			status = "DOWN"
		}
		b.WriteString(fmt.Sprintf("[%s] %s [%s] %v\n", status, t.Module, t.Host, t.Labels))
	}

	return mcp.NewToolResultText(b.String()), nil
}

func (s *Server) registerGetMetrics() {
	tool := mcp.NewTool("get_metrics",
		mcp.WithDescription("Get latest metrics for a specific target"),
		mcp.WithString("target",
			mcp.Required(),
			mcp.Description("Target identifier: host IP for icmp/snmp, domain for dns"),
		),
		mcp.WithString("module",
			mcp.Description("Module: icmp, snmp, dns (auto-detected if not specified)"),
		),
	)

	s.mcpServer.AddTool(tool, s.handleGetMetrics)
}

func (s *Server) handleGetMetrics(ctx context.Context, req mcp.CallToolRequest) (*mcp.CallToolResult, error) {
	target := argString(req, "target")
	module := argString(req, "module")

	if target == "" {
		return mcp.NewToolResultError("target is required"), nil
	}

	keys := s.findMetricKeys(target, module)

	if len(keys) == 0 {
		return mcp.NewToolResultText(fmt.Sprintf("No metrics found for target: %s", target)), nil
	}

	var b strings.Builder
	b.WriteString(fmt.Sprintf("Metrics for %s:\n\n", target))

	for _, key := range keys {
		ms := s.deps.Registry.Get(key)
		if len(ms) == 0 {
			continue
		}
		b.WriteString(fmt.Sprintf("--- %s ---\n", key))
		for _, m := range ms {
			labelStr := formatLabels(m.Labels)
			b.WriteString(fmt.Sprintf("  %s%s = %.3f\n", m.Name, labelStr, m.Value))
		}
		b.WriteString("\n")
	}

	return mcp.NewToolResultText(b.String()), nil
}

func (s *Server) findMetricKeys(target, module string) []string {
	var allKeys []string

	if module == "" || module == "icmp" {
		if key := "icmp/" + target; s.deps.Registry.Get(key) != nil {
			allKeys = append(allKeys, key)
		}
	}

	if module == "" || module == "dns" {
		for _, k := range s.deps.Registry.Keys() {
			if strings.HasPrefix(k, "dns/") && strings.Contains(k, target) {
				allKeys = append(allKeys, k)
			}
		}
	}

	if module == "" || module == "snmp" {
		if key := "snmp/" + target; s.deps.Registry.Get(key) != nil {
			allKeys = append(allKeys, key)
		}
	}

	return allKeys
}

func checkUp(registry *metrics.Registry, key string) bool {
	ms := registry.Get(key)
	if ms == nil {
		return true
	}
	for _, m := range ms {
		if strings.HasSuffix(m.Name, "_up") && m.Value == 0 {
			return false
		}
	}
	return true
}

func mergeLabels(labels map[string]string, kv ...string) map[string]string {
	m := make(map[string]string, len(labels)+len(kv)/2)
	for k, v := range labels {
		m[k] = v
	}
	for i := 0; i < len(kv)-1; i += 2 {
		m[kv[i]] = kv[i+1]
	}
	return m
}

func formatLabels(labels map[string]string) string {
	if len(labels) == 0 {
		return ""
	}
	data, err := json.Marshal(labels)
	if err != nil {
		return fmt.Sprintf("%v", labels)
	}
	return string(data)
}

package mcp

import (
	"context"
	"fmt"
	"net/http"
	"sync"

	"probe-agent/internal/config"
	"probe-agent/internal/metrics"
	mcpcore "github.com/mark3labs/mcp-go/mcp"
	"github.com/mark3labs/mcp-go/server"
	"go.uber.org/zap"
)

type Dependencies struct {
	Registry *metrics.Registry
	Config   *config.Config
	Logger   *zap.Logger
}

type Server struct {
	mcpServer  *server.MCPServer
	httpServer *server.StreamableHTTPServer
	auth       *APIKeyAuth
	deps       Dependencies
	cfg        config.MCPConfig
	handler    http.Handler
	httpSrv    *http.Server
	mu         sync.Mutex
}

func New(deps Dependencies, cfg config.MCPConfig) (*Server, error) {
	s := &Server{
		deps: deps,
		cfg:  cfg,
	}

	s.mcpServer = server.NewMCPServer(
		"probe-agent",
		"1.0.0",
		server.WithToolCapabilities(true),
	)

	s.registerTools()

	s.httpServer = server.NewStreamableHTTPServer(
		s.mcpServer,
		server.WithEndpointPath("/mcp"),
	)

	handler := http.Handler(s.httpServer)

	if cfg.Auth.Type == "api_key" && len(cfg.Auth.Keys) > 0 {
		s.auth = NewAPIKeyAuth(cfg.Auth.Keys)
		handler = AuthMiddleware(handler, s.auth)
		deps.Logger.Info("mcp api key auth enabled")
	}

	s.handler = handler

	return s, nil
}

func (s *Server) Handler() http.Handler {
	return s.handler
}

func (s *Server) Start(addr string) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.httpSrv != nil {
		return fmt.Errorf("mcp server already started")
	}

	s.httpSrv = &http.Server{
		Addr:    addr,
		Handler: s.handler,
	}

	s.deps.Logger.Info("mcp server starting",
		zap.String("addr", addr),
		zap.String("endpoint", "/mcp"),
	)

	go func() {
		if err := s.httpSrv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			s.deps.Logger.Error("mcp server error", zap.Error(err))
		}
	}()

	return nil
}

func (s *Server) Stop(ctx context.Context) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.httpSrv == nil {
		return nil
	}

	return s.httpSrv.Shutdown(ctx)
}

func (s *Server) registerTools() {
	s.registerGetTargets()
	s.registerGetMetrics()
}

func argString(req mcpcore.CallToolRequest, name string) string {
	if req.Params.Arguments == nil {
		return ""
	}
	v, ok := req.Params.Arguments[name]
	if !ok {
		return ""
	}
	s, _ := v.(string)
	return s
}

