	Port      uint16        `yaml:"port"`
	Timeout   time.Duration `yaml:"timeout"`
	Retries   int           `yaml:"retries"`
}

func (d *SNMPDefaults) Validate() {
	if d.Version == "" {
		d.Version = "2c"
	}
	if d.Community == "" {
		d.Community = "public"
	}
	if d.Port <= 0 {
		d.Port = 161
	}
	if d.Timeout <= 0 {
		d.Timeout = 5 * time.Second
	}
	if d.Retries <= 0 {
		d.Retries = 1
	}
}

