func TestRegistryConcurrent(t *testing.T) {
	r := NewRegistry()
	done := make(chan bool)

	for i := 0; i < 10; i++ {
		go func(n int) {
			key := string(rune('a' + n))
			r.Store(key, []Metric{{Name: key, Value: float64(n)}})
			_ = r.Get(key)
			_ = r.Keys()
			done <- true
		}(i)
	}

	for i := 0; i < 10; i++ {
		<-done
	}
}

