package selfmetrics

import (
	"testing"
)

func TestBuildVersion(t *testing.T) {
	if BuildVersion == "" {
		t.Error("BuildVersion should not be empty")
	}
}

func TestCountersZeroInit(t *testing.T) {
	if v := MetricsCollected.Load(); v != 0 {
		t.Errorf("MetricsCollected: expected 0, got %d", v)
	}
	if v := MetricsPushed.Load(); v != 0 {
		t.Errorf("MetricsPushed: expected 0, got %d", v)
	}
	if v := PushErrors.Load(); v != 0 {
		t.Errorf("PushErrors: expected 0, got %d", v)
	}
	if v := QueueLength.Load(); v != 0 {
		t.Errorf("QueueLength: expected 0, got %d", v)
	}
}

func TestCounterIncrement(t *testing.T) {
	MetricsCollected.Add(10)
	MetricsPushed.Add(5)
	PushErrors.Add(1)
	QueueLength.Store(100)

	if v := MetricsCollected.Load(); v != 10 {
		t.Errorf("MetricsCollected: expected 10, got %d", v)
	}
	if v := MetricsPushed.Load(); v != 5 {
		t.Errorf("MetricsPushed: expected 5, got %d", v)
	}
	if v := PushErrors.Load(); v != 1 {
		t.Errorf("PushErrors: expected 1, got %d", v)
	}
	if v := QueueLength.Load(); v != 100 {
		t.Errorf("QueueLength: expected 100, got %d", v)
	}

	MetricsCollected.Add(-10)
	MetricsPushed.Add(-5)
	PushErrors.Add(-1)
	QueueLength.Store(0)
}

package selfmetrics

import (
	"testing"
)

func TestCollectWithoutRuntime(t *testing.T) {
	targets := map[string]int{"icmp": 2, "dns": 3, "snmp": 1}
	ms := Collect(false, targets)

	var infoCount, uptimeCount, targetsCount int
	for _, m := range ms {
		switch m.Name {
		case "probe_agent_info":
			infoCount++
			if v := m.Labels["version"]; v != "dev" {
				t.Errorf("expected version dev, got %s", v)
			}
		case "probe_agent_uptime_seconds":
			uptimeCount++
			if m.Value <= 0 {
				t.Errorf("uptime should be > 0, got %f", m.Value)
			}
		case "probe_agent_targets":
			targetsCount++
		case "probe_agent_goroutines":
			t.Errorf("should not collect runtime metrics when disabled")
		}
	}

	if infoCount != 1 {
		t.Errorf("expected 1 info metric, got %d", infoCount)
	}
	if uptimeCount != 1 {
		t.Errorf("expected 1 uptime metric, got %d", uptimeCount)
	}
	if targetsCount != 3 {
		t.Errorf("expected 3 target metrics (icmp,dns,snmp), got %d", targetsCount)
	}
}

func TestCollectWithRuntime(t *testing.T) {
	ms := Collect(true, nil)

	found := make(map[string]bool)
	for _, m := range ms {
		found[m.Name] = true
	}

	runtimeMetrics := []string{
		"probe_agent_goroutines",
		"probe_agent_memory_alloc_bytes",
		"probe_agent_memory_heap_bytes",
		"probe_agent_memory_sys_bytes",
		"probe_agent_gc_pauses_total",
	}

	for _, name := range runtimeMetrics {
		if !found[name] {
			t.Errorf("missing runtime metric: %s", name)
		}
	}
}

func TestCollectEmptyTargets(t *testing.T) {
	ms := Collect(false, nil)
	for _, m := range ms {
		if m.Name == "probe_agent_targets" {
			t.Error("should not emit targets metric with nil map")
		}
	}
}

func TestCollectCounterMetrics(t *testing.T) {
	MetricsCollected.Add(42)
	MetricsPushed.Add(30)
	PushErrors.Add(2)

	ms := Collect(false, nil)

	for _, m := range ms {
		switch m.Name {
		case "probe_agent_metrics_collected_total":
			if m.Value != 42 {
				t.Errorf("expected 42, got %f", m.Value)
			}
		case "probe_agent_metrics_pushed_total":
			if m.Value != 30 {
				t.Errorf("expected 30, got %f", m.Value)
			}
		case "probe_agent_push_errors_total":
			if m.Value != 2 {
				t.Errorf("expected 2, got %f", m.Value)
			}
		}
	}

	MetricsCollected.Add(-42)
	MetricsPushed.Add(-30)
	PushErrors.Add(-2)
}

package selfmetrics

import (
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

type mockCounter struct {
	counts map[string]int
}

func (m mockCounter) Counts() map[string]int { return m.counts }

func TestHandlerContentType(t *testing.T) {
	MetricsCollected.Store(0)
	MetricsPushed.Store(0)
	PushErrors.Store(0)
	QueueLength.Store(0)

	h := Handler(false, mockCounter{map[string]int{"icmp": 1}})
	rec := httptest.NewRecorder()
	req := httptest.NewRequest(http.MethodGet, "/metrics", nil)
	h(rec, req)

	if ct := rec.Header().Get("Content-Type"); ct != "text/plain; version=0.0.4" {
		t.Errorf("expected text/plain; version=0.0.4, got %q", ct)
	}
}

func TestHandlerOutputFormat(t *testing.T) {
	MetricsCollected.Store(5)
	MetricsPushed.Store(3)
	PushErrors.Store(0)
	QueueLength.Store(0)

	h := Handler(false, mockCounter{map[string]int{"icmp": 2}})
	rec := httptest.NewRecorder()
	req := httptest.NewRequest(http.MethodGet, "/metrics", nil)
	h(rec, req)

	body := rec.Body.String()

	if !strings.Contains(body, "# HELP probe_agent_info") {
		t.Error("missing HELP line for probe_agent_info")
	}
	if !strings.Contains(body, "# TYPE probe_agent_info gauge") {
		t.Error("missing TYPE line for probe_agent_info")
	}
	if !strings.Contains(body, `probe_agent_info{goversion="`, version) {
		t.Error("missing label-encoded info metric")
	}
	if !strings.Contains(body, `probe_agent_targets{module="icmp"} 2`) {
		t.Error("missing targets metric with correct value")
	}
	if !strings.Contains(body, "probe_agent_metrics_collected_total 5") {
		t.Error("missing collected_total metric")
	}
}

func TestHandlerWithRuntime(t *testing.T) {
	h := Handler(true, nil)
	rec := httptest.NewRecorder()
	req := httptest.NewRequest(http.MethodGet, "/metrics", nil)
	h(rec, req)

	body := rec.Body.String()

	runtimeMetrics := []string{
		"probe_agent_goroutines",
		"probe_agent_memory_alloc_bytes",
		"probe_agent_gc_pauses_total",
	}
	for _, name := range runtimeMetrics {
		if !strings.Contains(body, name) {
			t.Errorf("missing runtime metric in output: %s", name)
		}
	}
}

func TestHandlerUptimePositive(t *testing.T) {
	h := Handler(false, nil)
	rec := httptest.NewRecorder()
	req := httptest.NewRequest(http.MethodGet, "/metrics", nil)
	h(rec, req)

	rec2 := httptest.NewRecorder()
	h(rec2, req)

	// uptime should increase between calls
	body1 := rec.Body.String()
	body2 := rec2.Body.String()
	if body1 == body2 {
		t.Log("uptime values may be equal if calls are very fast")
	}
}

