$old = '"probe-agent/'
$new = '"github.com/ZeroYe/probekit/'
Get-ChildItem -Recurse -Filter "*.go" | Select-String -Pattern $old -SimpleMatch | Select-Object -ExpandProperty Path -Unique | ForEach-Object {
    $content = Get-Content $_ -Raw
    if ($content -match [regex]::Escape($old)) {
        $content = $content -replace [regex]::Escape($old), $new
        Set-Content $_ $content -NoNewline
        Write-Host "updated: $_"
    }
}
